import React from 'react';
import { collection, getDocs, doc, updateDoc, getDoc } from 'firebase/firestore';
import GlassCard from './common/GlassCard';
import { COLORS, SAVINGS_INTEREST_TIERS, getSavingsInterestRate } from '../constants';

// Function to calculate monthly interest for a savings account
export const calculateMonthlySavingsInterest = (balance) => {
    const annualRate = getSavingsInterestRate(balance);
    const monthlyRate = annualRate / 12;
    return balance * monthlyRate;
};

// Function to apply monthly savings interest to all users
export const applyMonthlySavingsInterest = async (db, appId, earningsPool) => {
    try {
        // Get all users with savings accounts
        const usersRef = collection(db, `artifacts/${appId}/users`);
        const usersSnapshot = await getDocs(usersRef);
        
        let totalInterestPaid = 0;
        const updatedUsers = [];
        
        for (const userDoc of usersSnapshot.docs) {
            const userData = userDoc.data();
            if (userData.accounts && userData.accounts.Savings) {
                const savingsBalance = userData.accounts.Savings.balance || 0;
                if (savingsBalance > 0) {
                    const monthlyInterest = calculateMonthlySavingsInterest(savingsBalance);
                    
                    // Update user's savings balance
                    const updatedAccounts = { ...userData.accounts };
                    updatedAccounts.Savings.balance += monthlyInterest;
                    
                    // Add transaction record
                    const newTransaction = {
                        date: new Date().toLocaleDateString('en-US'),
                        description: `Monthly Interest Payment (${(getSavingsInterestRate(savingsBalance) * 100).toFixed(2)}% APY)`,
                        amount: monthlyInterest,
                        status: 'Completed',
                        type: 'Interest'
                    };
                    
                    const updatedTransactions = [...(userData.transactions || []), newTransaction];
                    
                    // Update user document
                    const userRef = doc(db, `artifacts/${appId}/users`, userDoc.id);
                    await updateDoc(userRef, {
                        accounts: updatedAccounts,
                        transactions: updatedTransactions
                    });
                    
                    totalInterestPaid += monthlyInterest;
                    updatedUsers.push({
                        id: userDoc.id,
                        name: userData.name,
                        interest: monthlyInterest,
                        newBalance: updatedAccounts.Savings.balance
                    });
                }
            }
        }
        
        // Update earnings pool (can go negative as per requirements)
        const newEarningsPool = earningsPool - totalInterestPaid;
        
        // Update bank document with new earnings pool and last application time
        const bankRef = doc(db, `artifacts/${appId}/bank`);
        await updateDoc(bankRef, {
            earningsPool: newEarningsPool,
            lastInterestApplication: new Date().toISOString(),
            totalInterestPaid: (earningsPool - newEarningsPool) + totalInterestPaid
        });
        
        return {
            success: true,
            totalInterestPaid,
            newEarningsPool,
            updatedUsers,
            message: `Interest applied to ${updatedUsers.length} savings accounts. Total paid: ₽${totalInterestPaid.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
        };
        
    } catch (error) {
        console.error('Error applying savings interest:', error);
        return {
            success: false,
            error: error.message,
            message: 'Failed to apply savings interest'
        };
    }
};

// Function to check if interest should be applied (every 12 hours)
export const shouldApplyInterest = (lastApplicationTime) => {
    if (!lastApplicationTime) return true;
    
    const lastApplication = new Date(lastApplicationTime);
    const now = new Date();
    const hoursSinceLastApplication = (now - lastApplication) / (1000 * 60 * 60);
    
    return hoursSinceLastApplication >= 12;
};

// Function to automatically apply interest if 12 hours have passed
export const autoApplyInterestIfNeeded = async (db, appId) => {
    try {
        // Get bank document to check last application time
        const bankRef = doc(db, `artifacts/${appId}/bank`);
        const bankSnap = await getDoc(bankRef);
        
        if (!bankSnap.exists()) {
            console.log('Bank document not found, creating initial structure');
            return false;
        }
        
        const bankData = bankSnap.data();
        const { lastInterestApplication, earningsPool } = bankData;
        
        if (shouldApplyInterest(lastInterestApplication)) {
            console.log('12 hours have passed, applying savings interest automatically');
            const result = await applyMonthlySavingsInterest(db, appId, earningsPool);
            return result;
        } else {
            console.log('Interest application not due yet');
            return false;
        }
        
    } catch (error) {
        console.error('Error in auto-apply interest check:', error);
        return false;
    }
};

// Function to get interest rate display for a balance
export const getInterestRateDisplay = (balance) => {
    const rate = getSavingsInterestRate(balance);
    return `${(rate * 100).toFixed(1)}% APY`;
};

// Function to get next tier information
export const getNextTierInfo = (balance) => {
    for (let i = 0; i < SAVINGS_INTEREST_TIERS.length; i++) {
        if (balance < SAVINGS_INTEREST_TIERS[i].maxBalance) {
            const nextTier = SAVINGS_INTEREST_TIERS[i];
            const amountNeeded = nextTier.minBalance - balance;
            return {
                nextTier: nextTier,
                amountNeeded: amountNeeded,
                rateIncrease: nextTier.rate - getSavingsInterestRate(balance)
            };
        }
    }
    return null; // Already at highest tier
};

// React component for displaying savings interest information
const SavingsInterestDisplay = ({ savingsBalance, onApplyInterest }) => {
    const currentRate = getSavingsInterestRate(savingsBalance);
    const monthlyInterest = calculateMonthlySavingsInterest(savingsBalance);
    const nextTierInfo = getNextTierInfo(savingsBalance);
    
    return (
        <GlassCard className="p-6">
            <h3 className="text-2xl font-bold mb-4" style={{ color: COLORS.primaryAccent }}>
                💰 Savings Interest Calculator
            </h3>
            
            <div className="space-y-4">
                <div className="bg-gray-800 rounded-lg p-4">
                    <div className="text-sm text-gray-400">Current Balance</div>
                    <div className="text-2xl font-bold">₽{savingsBalance.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</div>
                </div>
                
                <div className="bg-gray-800 rounded-lg p-4">
                    <div className="text-sm text-gray-400">Current Interest Rate</div>
                    <div className="text-xl font-bold" style={{ color: COLORS.primaryAccent }}>
                        {(currentRate * 100).toFixed(1)}% APY
                    </div>
                </div>
                
                <div className="bg-gray-800 rounded-lg p-4">
                    <div className="text-sm text-gray-400">Monthly Interest</div>
                    <div className="text-xl font-bold text-green-400">
                        ₽{monthlyInterest.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </div>
                    <div className="text-xs text-gray-400 mt-1">
                        Automatically applied every 12 hours
                    </div>
                </div>
                
                {nextTierInfo && (
                    <div className="bg-blue-900 rounded-lg p-4">
                        <div className="text-sm text-blue-300">Next Tier</div>
                        <div className="text-lg font-bold text-blue-200">
                            {(nextTierInfo.nextTier.rate * 100).toFixed(1)}% APY
                        </div>
                        <div className="text-sm text-blue-300">
                            Add ₽{nextTierInfo.amountNeeded.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} to reach next tier
                        </div>
                    </div>
                )}
                
                <div className="bg-gray-800 rounded-lg p-4">
                    <div className="text-sm text-gray-400">Interest Tiers</div>
                    <div className="space-y-2">
                        {SAVINGS_INTEREST_TIERS.map((tier, index) => (
                            <div key={index} className="flex justify-between items-center">
                                <span className="text-sm">
                                    ₽{tier.minBalance.toLocaleString()} - ₽{tier.maxBalance.toLocaleString()}
                                </span>
                                <span className={`font-semibold ${savingsBalance >= tier.minBalance && savingsBalance <= tier.maxBalance ? 'text-green-400' : 'text-gray-400'}`}>
                                    {(tier.rate * 100).toFixed(1)}%
                                </span>
                            </div>
                        ))}
                    </div>
                </div>
                
                <div className="bg-blue-900 rounded-lg p-4">
                    <div className="text-sm text-blue-300">Funding Source</div>
                    <div className="text-xs text-blue-200">
                        Interest payments are funded from the bank's Earnings Pool. The bank may go into negative earnings if needed.
                    </div>
                </div>
                
                {onApplyInterest && (
                    <button
                        onClick={onApplyInterest}
                        className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-6 rounded-lg transition-colors duration-200"
                    >
                        Apply Monthly Interest
                    </button>
                )}
            </div>
        </GlassCard>
    );
};

export default SavingsInterestDisplay;