import React from 'react';

const TransactionHistory = ({ userProfile, COLORS, transactionLimit = 10, onLoadMore }) => {
    const transactions = Array.isArray(userProfile.transactions)
        ? [...userProfile.transactions].reverse().slice(0, transactionLimit)
        : [];

    return (
        <div className="w-full max-w-4xl mx-auto">
            <h2 className="text-2xl font-bold mb-4" style={{ color: COLORS.primaryAccent }}>Transaction History</h2>
            <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-gray-700">
                    <thead>
                        <tr>
                            <th className="py-2 px-4 text-left">Date</th>
                            <th className="py-2 px-4 text-left">Description</th>
                            <th className="py-2 px-4 text-right">Amount</th>
                            <th className="py-2 px-4 text-left">Status</th>
                        </tr>
                    </thead>
                    <tbody>
                        {transactions.length > 0 ? (
                            transactions.map((txn, idx) => (
                                <tr key={idx} className="hover:bg-white hover:bg-opacity-10 transition-colors duration-200">
                                    <td className="py-2 px-4">{txn.date}</td>
                                    <td className="py-2 px-4">{txn.description}</td>
                                    <td className="py-2 px-4 text-right">{txn.amount >= 0 ? '+' : ''}₽{Math.abs(txn.amount).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</td>
                                    <td className="py-2 px-4">{txn.status}</td>
                                </tr>
                            ))
                        ) : (
                            <tr>
                                <td colSpan={4} className="py-4 text-center text-gray-400">No transactions yet.</td>
                            </tr>
                        )}
                    </tbody>
                </table>
            </div>
            {userProfile.transactions && userProfile.transactions.length > transactionLimit && (
                <div className="flex justify-center mt-4">
                    <button
                        onClick={onLoadMore}
                        className="px-6 py-2 rounded-lg font-bold bg-green-600 text-white hover:bg-green-700 transition-colors duration-200"
                    >
                        Load More
                    </button>
                </div>
            )}
        </div>
    );
};

export default TransactionHistory;
