import React, { useState } from 'react';

const iconStyle = { marginRight: 8, verticalAlign: 'middle' };

// Example props: { totalFunds, loansIssued, creditBalances, investments, earningsPool }
const BankLedger = ({
    totalFunds,
    loansIssued,
    creditBalances,
    investments,
    earningsPool,
    liquidFunds,
    minLiquidityPercent = 20,
    riskFlag,
    blockNewAccounts,
    pendingRequests,
    onClose
}) => {
    const [showModal, setShowModal] = useState(false);
    const liquidityPercent = (liquidFunds / totalFunds) * 100;

    return (
        <div className="fixed inset-0 bg-black bg-opacity-70 flex items-center justify-center z-50">
            <div className="bg-[#181c1f] rounded-2xl shadow-2xl p-10 max-w-3xl w-full relative text-white overflow-y-auto" style={{ maxHeight: '90vh' }}>
                <button
                    className="absolute top-4 right-4 text-2xl text-gray-400 hover:text-white"
                    onClick={onClose}
                >×</button>
                <h2 className="text-3xl font-extrabold mb-6 text-[#00ffb3] flex items-center gap-2">🏦 Bank Ledger Breakdown</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                    <div className="bg-[#23272b] rounded-lg p-6">
                        <>
                            <div className="text-gray-400 text-xs mb-1">Total Bank Funds</div>
                            <div className="font-bold text-2xl">₽{totalFunds.toLocaleString()}</div>
                        </>
                    </div>
                    <div className="bg-[#23272b] rounded-lg p-6">
                        <>
                            <div className="text-gray-400 text-xs mb-1">Earnings Pool</div>
                            <div className="font-bold text-2xl">₽{earningsPool.toLocaleString()}</div>
                            {earningsPool < 0 && (
                                <div className="text-xs text-red-400 mt-1">
                                    ⚠️ Negative balance
                                </div>
                            )}
                        </>
                    </div>
                    <div className="bg-[#23272b] rounded-lg p-6">
                        <>
                            <div className="text-gray-400 text-xs mb-1">Loans Issued</div>
                            <div className="font-bold text-xl">
                                ₽{loansIssued.toLocaleString()} <span className="text-sm text-gray-400">({((loansIssued/totalFunds)*100).toFixed(1)}%)</span>
                            </div>
                        </>
                    </div>
                    <div className="bg-[#23272b] rounded-lg p-6">
                        <>
                            <div className="text-gray-400 text-xs mb-1">Credit Balances</div>
                            <div className="font-bold text-xl">
                                ₽{creditBalances.toLocaleString()} <span className="text-xl">({((creditBalances/totalFunds)*100).toFixed(1)}%)</span>
                            </div>
                        </>
                    </div>
                    <div className="bg-[#23272b] rounded-lg p-6">
                        <>
                            <div className="text-gray-400 text-xs mb-1">Investments</div>
                            <div className="font-bold text-xl">
                                ₽{investments.toLocaleString()} <span className="text-sm text-gray-400">({((investments/totalFunds)*100).toFixed(1)}%)</span>
                            </div>
                        </>
                    </div>
                    <div className="bg-[#23272b] rounded-lg p-6">
                        <>
                            <div className="text-gray-400 text-xs mb-1">Liquid Funds</div>
                            <div className="font-bold text-xl">
                                ₽{liquidFunds.toLocaleString()} <span className="text-sm text-gray-400">({liquidityPercent.toFixed(1)}%)</span>
                            </div>
                        </>
                    </div>
                </div>
                {liquidityPercent < minLiquidityPercent && (
                    <div className="bg-red-700 text-white font-bold rounded-lg p-4 mb-4 text-center">
                        🔴 Liquidity Risk: Below Minimum Threshold
                    </div>
                )}
                {blockNewAccounts && (
                    <div className="bg-yellow-600 text-white font-bold rounded-lg p-4 mb-4 text-center">
                        🚫 New loans, investments, and savings account creation are blocked until liquidity is restored.
                    </div>
                )}
                
                {/* Savings Interest System Info */}
                <div className="bg-blue-900 rounded-lg p-4 mb-4">
                    <div className="text-blue-300 font-semibold mb-2">💰 Savings Interest System</div>
                    <div className="text-sm text-blue-200 space-y-1">
                        <div>• Interest automatically applied every 12 hours</div>
                        <div>• Tiered rates: 4.0% - 6.0% APY based on balance</div>
                        <div>• Funded from Earnings Pool (may go negative)</div>
                    </div>
                </div>
                
                {/* Add more detailed breakdowns, charts, and flowing sections here as needed */}
                {/* Example: Pie chart, investment breakdown, savings interest, etc. */}
            </div>
        </div>
    );
};

export default BankLedger;
