import React from 'react';
import { COLORS, getSavingsInterestRate } from '../../constants';
import GlassCard from '../common/GlassCard';
import SavingsInterestDisplay from '../SavingsInterestEngine';

const AccountOverview = ({
    userProfile,
    setUserProfile,
    showMessage,
    appId,
    db,
    auth,
    showAccountCardModal,
    setShowAccountCardModal,
    selectedAccountCardDetails,
    setSelectedAccountCardDetails,
    handleAccountCardClick,
    handlePayrollButtonClick // <-- renamed from handleOpenPayroll
}) => {
    if (!userProfile) return null;

    // Helper to generate card details for Checking, Business, and CreditCard accounts
    const getCardDetails = (type, acc) => {
        const generateSegment = () => Math.floor(1000 + Math.random() * 9000).toString();
        if (type === 'Personal' || type === 'Checking') {
            // Use user's debitCard if available, else generate a mock
            return {
                type: 'Debit',
                accountType: 'Checking',
                number: userProfile.debitCard?.number || `XXXX ${generateSegment()} ${generateSegment()} ${generateSegment()}`,
                expiry: userProfile.debitCard?.expiry || 'MM/YY',
                cvv: userProfile.debitCard?.cvv || 'XXX',
                pin: userProfile.debitCard?.pin || 'XXXX',
                accountNumber: acc.accountNumber
            };
        }
        if (type === 'Business') {
            // Generate a mock business debit card
            return {
                type: 'Business Debit',
                accountType: 'Business',
                number: `5XXX ${generateSegment()} ${generateSegment()} ${generateSegment()}`,
                expiry: '12/28',
                cvv: '987',
                pin: '5678',
                accountNumber: acc.accountNumber,
                // Add a displayTitle for correct modal title rendering
                displayTitle: 'Business Debit Card'
            };
        }
        if (type === 'CreditCard') {
            // Use user's debitCard if available, else generate a mock credit card
            return {
                type: 'Credit',
                accountType: 'Credit Card',
                number: userProfile.debitCard?.number || `4XXX ${generateSegment()} ${generateSegment()} ${generateSegment()}`,
                expiry: userProfile.debitCard?.expiry || 'MM/YY',
                cvv: userProfile.debitCard?.cvv || 'XXX',
                pin: userProfile.debitCard?.pin || 'XXXX',
                accountNumber: acc.accountNumber
            };
        }
        // For all other accounts (e.g., Savings), return null (no card)
        return null;
    };

    // Prepare account list for display
    const accounts = Object.entries(userProfile.accounts || {}).filter(
        ([key, acc]) =>
            typeof acc === 'object' &&
            acc !== null &&
            key !== 'CreditCardLimit'
    );

    return (
        <div className="w-full max-w-4xl mx-auto">
            <h2 className="text-3xl font-bold mb-6" style={{ color: COLORS.primaryAccent }}>
                Account Overview
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {accounts.length === 0 && (
                    <GlassCard className="p-6 text-center">
                        <p className="text-lg" style={{ color: COLORS.typography }}>
                            No accounts found.
                        </p>
                    </GlassCard>
                )}
                {accounts.map(([type, acc]) => {
                    // Only allow card details for Checking, Business, CreditCard
                    const showCard =
                        type === 'Personal' ||
                        type === 'Checking' ||
                        type === 'Business' ||
                        type === 'CreditCard';
                    return (
                        <div
                            key={type}
                            tabIndex={showCard ? 0 : -1}
                            role={showCard ? 'button' : undefined}
                            className={showCard ? "focus:outline-none" : ""}
                            // Only trigger card details on card click if NOT business, otherwise do nothing (buttons handle actions)
                            onClick={e => {
                                if (
                                    showCard &&
                                    handleAccountCardClick &&
                                    type !== 'Business'
                                ) {
                                    handleAccountCardClick(type, acc, e);
                                }
                            }}
                            onKeyPress={e => {
                                if (
                                    showCard &&
                                    (e.key === 'Enter' || e.key === ' ') &&
                                    type !== 'Business'
                                ) {
                                    handleAccountCardClick(type, acc, e);
                                }
                            }}
                        >
                            <GlassCard className={`p-6 flex flex-col justify-between ${showCard ? 'hover:shadow-xl hover:scale-105 cursor-pointer' : ''} transition-transform duration-200`}>
                                <div>
                                    <h3 className="text-xl font-semibold mb-2" style={{ color: COLORS.primaryAccent }}>
                                        {type === 'Personal' ? 'Checking' : type} Account
                                    </h3>
                                    <p className="text-lg mb-2" style={{ color: COLORS.typography }}>
                                        Balance: <span className="font-bold" style={{ color: COLORS.success }}>
                                            ₽{(acc.balance ?? 0).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                        </span>
                                    </p>
                                    <p className="text-sm text-gray-400 mb-2">
                                        Account Number: {acc.accountNumber}
                                    </p>
                                </div>
                                {showCard && (
                                    <button
                                        onClick={e => { e.stopPropagation(); handleAccountCardClick(type, acc, e); }}
                                        className="mt-4 px-4 py-2 rounded-lg font-bold bg-blue-600 text-white hover:bg-blue-700 transition-colors duration-200"
                                    >
                                        Show Card Details
                                    </button>
                                )}
                                {type === 'Business' && (
                                    <button
                                        className="mt-4 px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 font-bold"
                                        onClick={e => { e.stopPropagation(); handlePayrollButtonClick(acc, e); }}
                                    >
                                        Payroll
                                    </button>
                                )}
                            </GlassCard>
                        </div>
                    );
                })}
            </div>
            
            {/* Savings Interest Display - Only show if user has a Savings account */}
            {userProfile.accounts?.Savings && (
                <div className="mt-8">
                    <SavingsInterestDisplay 
                        savingsBalance={userProfile.accounts.Savings.balance || 0}
                        onApplyInterest={null} // Users can't apply interest themselves
                    />
                </div>
            )}
        </div>
    );
};

export default AccountOverview;
